    60→	private getModelId(): string {
    61→		if (!this.modelId) {
    62→			throw new Error(
    63→				'Neural search model not available. Run: npm run cli:dev -- bootstrap-neural-search',
    64→			);
    65→		}
    66→		return this.modelId;
    67→	}
