    87→	private normalizeQuery({ text }: { text: string }): string {
    88→		let normalized = text.toLowerCase().trim();
    89→
    90→		for (const [pattern, replacement] of this.QUERY_SYNONYMS) {
    91→			normalized = normalized.replace(pattern, replacement);
    92→		}
    93→
    94→		return normalized;
    95→	}
