   185→	@LogExecution({ logParams: false, logResponse: false })
   186→	async bulkIndexProducts({
   187→		indexName,
   188→		styles,
   189→	}: {
   190→		indexName: string;
   191→		styles: IStylesMvBase[];
   192→	}): Promise<{ indexed: number; errors: number }> {
   193→		if (styles.length === 0) {
   194→			return { indexed: 0, errors: 0 };
   195→		}
   196→
   197→		const documents = styles.map((style) =>
   198→			this.transformStyleToOpensearchProduct({ style }),
   199→		);
   200→
   201→		return this.opensearchService.bulkIndex({ indexName, documents });
   202→	}
