   205→		paramFormatter: (params: [{ queryText: string; size: number }]) => ({
   206→			queryText: params[0].queryText,
   207→			size: params[0].size,
   208→		}),
   209→		responseFormatter: (response: IOpensearchProduct[]) => ({
