   213→	async searchProducts({
   214→		queryText,
   215→		size = 20,
   216→	}: {
   217→		queryText: string;
   218→		size?: number;
   219→	}): Promise<IOpensearchProduct[]> {
   220→		const normalizedQuery = this.normalizeQuery({ text: queryText });
   221→		const hits = await this.opensearchService.search({
   222→			indexName: this.indexName,
   223→			searchPipeline: 'hybrid-search-pipeline',
   224→			body: {
   225→				size,
   226→				query: {
   227→					hybrid: {
   228→						queries: [
   229→							{
   230→								bool: {
   231→									should: [
   232→										{ match_phrase: { name: { query: normalizedQuery, boost: 5 } } },
   233→										{ match: { name: { query: normalizedQuery, boost: 3 } } },
   234→										{ match: { features: { query: normalizedQuery, boost: 1 } } },
   235→									],
   236→									filter: [{ term: { status: 'active' } }],
   237→								},
   238→							},
   239→							{
   240→								neural: {
   241→									product_embedding: {
   242→										query_text: normalizedQuery,
   243→										model_id: this.getModelId(),
   244→										k: size,
   245→										filter: { term: { status: 'active' } },
   246→									},
   247→								},
   248→							},
   249→						],
   250→					},
   251→				},
   252→				_source: { excludes: ['product_embedding', 'combined_text_for_embedding'] },
   253→			},
   254→		});
   255→
   256→		return hits.slice(0, size).map((hit) => ({
   257→			...(hit._source as IOpensearchProduct),
   258→			_id: hit._id,
   259→		}));
   260→	}
