   262→	private normalizeCondensedFeatures({
   263→		condensedFeatures,
   264→	}: {
   265→		condensedFeatures: unknown;
   266→	}): string[] | null {
   267→		if (condensedFeatures === null || condensedFeatures === undefined) {
   268→			return null;
   269→		}
   270→
   271→		if (typeof condensedFeatures === 'string') {
   272→			return [condensedFeatures];
   273→		}
   274→
   275→		if (Array.isArray(condensedFeatures)) {
   276→			return condensedFeatures.map(String);
   277→		}
   278→
   279→		if (typeof condensedFeatures === 'object') {
   280→			return Object.values(condensedFeatures).flatMap((value: unknown) =>
   281→				Array.isArray(value) ? value.map(String) : [String(value)],
   282→			);
   283→		}
   284→
   285→		return [JSON.stringify(condensedFeatures)];
   286→	}
