   288→	private buildCombinedTextForEmbedding({ style }: { style: IStylesMvBase }): string {
   289→		const condensed = this.normalizeCondensedFeatures({
   290→			condensedFeatures: style.condensed_features,
   291→		});
   292→
   293→		const parts: (string | null | undefined)[] = [
   294→			style.name,
   295→			style.product_type,
   296→			style.primary_category_name,
   297→			style.sub_category_names?.join(', '),
   298→			style.broad_category_names?.join(', '),
   299→			style.features,
   300→			style.general_comments,
   301→			style.decoration_method,
   302→			style.manufacturer,
   303→			style.brand?.join(', '),
   304→			style.style_type,
   305→			condensed?.join(', '),
   306→		];
   307→
   308→		return parts.filter(Boolean).join(' | ');
   309→	}
