   312→		style,
   313→	}: {
   314→		style: IStylesMvBase;
   315→	}): IOpensearchProduct {
   316→		return {
   317→			_id: style._id,
   318→			style_id: style.style_id,
   319→			product_id: style.product_id,
   320→			name: style.name ?? '',
   321→			features: style.features,
   322→			general_comments: style.general_comments,
   323→			decoration_method: style.decoration_method,
   324→			manufacturer: style.manufacturer,
   325→			primary_category_id: style.primary_category_id,
   326→			primary_category_name: style.primary_category_name,
   327→			product_type: style.product_type,
   328→			style_type: style.style_type,
   329→			broad_category_names: style.broad_category_names,
   330→			sub_category_names: style.sub_category_names,
   331→			minimum_quantity: style.minimum_quantity,
   332→			min_qty: style.min_qty,
   333→			default_quote_qty: style.default_quote_qty,
   334→			sizes: style.sizes,
   335→			turn_time: style.turn_time,
   336→			rush_turn_time: style.rush_turn_time,
   337→			no_minimum: style.no_minimum ? 1 : 0,
   338→			price_level: style.price_level,
   339→			rating_score: style.rating_score !== null ? Number(style.rating_score) : null,
   340→			rating_count: style.rating_count,
   341→			default_unit_prices: style.default_unit_prices,
   342→			colors: style.colors,
   343→			style_card_image_url: style.style_card_image_url,
   344→			link: style.link,
   345→			brand: style.brand,
   346→			condensed_features: this.normalizeCondensedFeatures({
   347→				condensedFeatures: style.condensed_features,
   348→			}),
   349→			status: style.status,
   350→			created_at:
   351→				style.created_at instanceof Date
   352→					? style.created_at.toISOString()
   353→					: String(style.created_at),
   354→			updated_at:
   355→				style.updated_at instanceof Date
   356→					? style.updated_at.toISOString()
   357→					: String(style.updated_at),
